async function seed() {
  console.log(`Seeding ${grantData.length} grants...`);

  for (const grant of grantData) {
    await db.insert(grants).values({
      ...grant,
      category: grant.category as any,
      fundingType: grant.fundingType as any,
      isActive: grant.isActive as any,
      isInstantFunding: grant.isInstantFunding as any,
      requirements: grant.requirements as any,
    });
  }

  console.log("Seeded successfully!");
  connection.end();
}

seed().catch((err) => {
  console.error("Seed error:", err);
  connection.end();
  process.exit(1);
});
